#include <bits/stdc++.h>
using namespace std;
int n,m,ans=1,d[1003],dist[1003];
bool b[1003][1003],edge[1003][1003];
vector<int> g[1003];
int main(){
	scanf("%d%d",&n,&m);
	for(int i=1;i<=m;i++){
		int len,s,t;
		scanf("%d",&len);
		for(int j=1;j<=len;j++){
			int p;
			scanf("%d",&p);
			b[i][p]=1;
			if(j==1)
				s=p;
			if(j==len)
				t=p;
		}
		for(int j=s;j<=t;j++)
			if(b[i][j])
				for(int k=s;k<=t;k++)
					if(!b[i][k] && !edge[k][j])
						edge[k][j]=1,g[k].push_back(j),d[j]++;
	}
	queue<int> s,t;
	for(int i=1;i<=n;i++)
		if(!d[i])
			t.push(i),dist[i]=1;
	while(t.size()){
		s.push(t.front()),t.pop();
		int x=s.back(),len=g[x].size();
		for(int i=0;i<len;i++)
			if(!--d[g[x][i]])
				t.push(g[x][i]),dist[g[x][i]]=dist[x]+1,ans=max(ans,dist[g[x][i]]);
	}
	printf("%d",ans);
	return 0;
}
